/* Auto-generated by gen_dct3_n8.py — DCT-III N=8 codelet (FFTW REDFT01).
 *   Y[k] = X[0] + 2 * sum_{n=1..7} X[n] * cos(π n (2k+1) / 16)
 * Layout: in[n*K + k] for n=0..7, k=0..K-1; out same shape. */

#ifndef DCT3_N8_AVX2_H
#define DCT3_N8_AVX2_H
#include <stddef.h>
#include <immintrin.h>

__attribute__((target("avx2,fma"))) static void
dct3_n8_avx2(const double * __restrict__ in,
             double * __restrict__ out,
             size_t K)
{
    const __m256d D1 = _mm256_set1_pd(1.96157056080646086116);
    const __m256d D2 = _mm256_set1_pd(1.84775906502257347697);
    const __m256d D3 = _mm256_set1_pd(1.66293922460509047134);
    const __m256d D4 = _mm256_set1_pd(1.41421356237309514547);
    const __m256d D5 = _mm256_set1_pd(1.11114046603920457734);
    const __m256d D6 = _mm256_set1_pd(0.76536686473017967458);
    const __m256d D7 = _mm256_set1_pd(0.39018064403225666270);

    size_t k = 0;
    for (; k + 4 <= K; k += 4) {
        __m256d x0 = _mm256_loadu_pd(&in[0*K + k]);
        __m256d x1 = _mm256_loadu_pd(&in[1*K + k]);
        __m256d x2 = _mm256_loadu_pd(&in[2*K + k]);
        __m256d x3 = _mm256_loadu_pd(&in[3*K + k]);
        __m256d x4 = _mm256_loadu_pd(&in[4*K + k]);
        __m256d x5 = _mm256_loadu_pd(&in[5*K + k]);
        __m256d x6 = _mm256_loadu_pd(&in[6*K + k]);
        __m256d x7 = _mm256_loadu_pd(&in[7*K + k]);

        /* Even part E[0..3] (uses x0, x2, x4, x6) */
        __m256d t  = _mm256_mul_pd(D4, x4);     /* 2*c4 * X[4] */
        __m256d a  = _mm256_add_pd(x0, t);      /* X[0] + 2c4 X[4] */
        __m256d b  = _mm256_sub_pd(x0, t);      /* X[0] - 2c4 X[4] */
        __m256d p  = _mm256_fmadd_pd(D2, x2, _mm256_mul_pd(D6, x6));   /* 2c2 X[2] + 2c6 X[6] */
        __m256d q  = _mm256_fmsub_pd(D6, x2, _mm256_mul_pd(D2, x6));   /* 2c6 X[2] - 2c2 X[6] */
        __m256d E0 = _mm256_add_pd(a, p);
        __m256d E3 = _mm256_sub_pd(a, p);
        __m256d E1 = _mm256_add_pd(b, q);
        __m256d E2 = _mm256_sub_pd(b, q);

        /* Odd part O[0..3] (uses x1, x3, x5, x7).
         * Same matrix shape as DCT-II's Y[1,3,5,7] applied to direct inputs. */
        __m256d O0 = _mm256_fmadd_pd(D1, x1, _mm256_mul_pd(D3, x3));
        O0 = _mm256_fmadd_pd(D5, x5, O0);
        O0 = _mm256_fmadd_pd(D7, x7, O0);

        __m256d O1 = _mm256_fmsub_pd(D3, x1, _mm256_mul_pd(D7, x3));
        O1 = _mm256_fnmadd_pd(D1, x5, O1);
        O1 = _mm256_fnmadd_pd(D5, x7, O1);

        __m256d O2 = _mm256_fmsub_pd(D5, x1, _mm256_mul_pd(D1, x3));
        O2 = _mm256_fmadd_pd(D7, x5, O2);
        O2 = _mm256_fmadd_pd(D3, x7, O2);

        __m256d O3 = _mm256_fmsub_pd(D7, x1, _mm256_mul_pd(D5, x3));
        O3 = _mm256_fmadd_pd(D3, x5, O3);
        O3 = _mm256_fnmadd_pd(D1, x7, O3);

        /* Y[k] = E[k] + O[k], Y[7-k] = E[k] - O[k] for k=0..3 */
        _mm256_storeu_pd(&out[0*K + k], _mm256_add_pd(E0, O0));
        _mm256_storeu_pd(&out[7*K + k], _mm256_sub_pd(E0, O0));
        _mm256_storeu_pd(&out[1*K + k], _mm256_add_pd(E1, O1));
        _mm256_storeu_pd(&out[6*K + k], _mm256_sub_pd(E1, O1));
        _mm256_storeu_pd(&out[2*K + k], _mm256_add_pd(E2, O2));
        _mm256_storeu_pd(&out[5*K + k], _mm256_sub_pd(E2, O2));
        _mm256_storeu_pd(&out[3*K + k], _mm256_add_pd(E3, O3));
        _mm256_storeu_pd(&out[4*K + k], _mm256_sub_pd(E3, O3));
    }

    /* Scalar tail */
    for (; k < K; k++) {
        double x0 = in[0*K + k];
        double x1 = in[1*K + k];
        double x2 = in[2*K + k];
        double x3 = in[3*K + k];
        double x4 = in[4*K + k];
        double x5 = in[5*K + k];
        double x6 = in[6*K + k];
        double x7 = in[7*K + k];
        const double d1=1.96157056080646086116, d2=1.84775906502257347697, d3=1.66293922460509047134;
        const double d4=1.41421356237309514547, d5=1.11114046603920457734, d6=0.76536686473017967458, d7=0.39018064403225666270;
        double t = d4*x4;
        double a = x0 + t, b = x0 - t;
        double p = d2*x2 + d6*x6;
        double q = d6*x2 - d2*x6;
        double E0=a+p, E3=a-p, E1=b+q, E2=b-q;
        double O0 = d1*x1 + d3*x3 + d5*x5 + d7*x7;
        double O1 = d3*x1 - d7*x3 - d1*x5 - d5*x7;
        double O2 = d5*x1 - d1*x3 + d7*x5 + d3*x7;
        double O3 = d7*x1 - d5*x3 + d3*x5 - d1*x7;
        out[0*K+k]=E0+O0;  out[7*K+k]=E0-O0;
        out[1*K+k]=E1+O1;  out[6*K+k]=E1-O1;
        out[2*K+k]=E2+O2;  out[5*K+k]=E2-O2;
        out[3*K+k]=E3+O3;  out[4*K+k]=E3-O3;
    }
}

#endif /* DCT3_N8_AVX2_H */
